import React, { useState, useEffect, useRef, useCallback } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI, Type } from "@google/genai";
import { Ship, Anchor, Fish, Utensils, Dice5, Coins, User, Waves, Sailboat, LifeBuoy, Bot, Play, Sparkles, AlertTriangle, X, Camera, RefreshCw, Smartphone, QrCode, MessageSquare, Wifi, WifiOff, Heart, ChevronLeft, ChevronRight, Clapperboard, ScrollText, Volume2, Users, Vibrate, Loader2, Save, Trash2, LogOut, TrendingUp, CloudLightning, Sun, Cloud, Snowflake, Trophy, MapPin, Clock, Maximize2, Minimize2 } from 'lucide-react';

// --- Constants & Types ---

const BOARD_SIZE = 16;
