const SAVE_KEY = 'maigreifinn_save_v2';

// Faster AI Timings
const AI_THINK_TIME = 800;
const AI_ACTION_DELAY = 600;

type SpaceType = 'START' | 'BOAT' | 'RESTAURANT' | 'CHANCE' | 'STORM' | 'JAIL' | 'GO_TO_JAIL' | 'FREE_PARKING';
