}

interface Player {
  id: number;
  name: string;
  color: string;
  position: number;
  money: number;
  hunger: number;
  karma: number;
  isJailed: boolean;
  inventory: number[];
  isAi: boolean;
  boatType: BoatType;
  portraitUrl?: string;
  selfieData?: string;
  age?: number;
  gender?: string;
  job?: string;
