async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 2000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    if (retries > 0) {
      const isServiceError = error.status === 503 || error.message?.includes('503') || error.status === 429;
      if (isServiceError) {
          await new Promise(resolve => setTimeout(resolve, delay));
          return withRetry(fn, retries - 1, delay * 1.5);
      }
    }
    throw error;
  }
}

// Helper to calculate Net Worth
const getNetWorth = (player: Player, board: BoardSpace[]) => {
    const propertyValue = player.inventory.reduce((total, spaceId) => {
        const space = board.find(s => s.id === spaceId);
        return total + (space?.price || 0);
    }, 0);
    return player.money + propertyValue;
};

