                <div className={`absolute inset-0 bg-gradient-to-t ${isCorner ? 'from-slate-900/80 via-transparent' : 'from-slate-950 via-slate-950/20 to-transparent'}`}></div>
            </div>

            {/* Content */}
            <div className="relative z-10 h-full p-2 flex flex-col justify-between">
                <div className="flex justify-between items-start">
                    <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded bg-black/60 backdrop-blur ${
                        space.type === 'BOAT' ? 'text-cyan-300' : 
                        space.type === 'RESTAURANT' ? 'text-amber-300' : 
                        space.type === 'JAIL' || space.type === 'GO_TO_JAIL' ? 'text-red-400' : 
                        isCorner ? 'text-white' : 'text-slate-300'
                    }`}>{space.name}</span>

                    {space.owner !== undefined && space.owner !== null && (
                        <div className={`w-3 h-3 rounded-full ${players[space.owner].color} border border-white shadow`}></div>
