    }
};

// --- Helpers ---

const getAi = () => {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

async function withRetry<T>(fn: () => Promise<T>, retries = 3): Promise<T> {
    try {
        return await fn();
    } catch (e) {
        if (retries > 0) {
            await new Promise(r => setTimeout(r, 1000));
            return withRetry(fn, retries - 1);
        }
        throw e;
    }
}

