    { id: 'b_small', name: 'Coastal Cutter', type: 'SMALL_BOAT', maxFuel: 80, maxHold: 300, resilience: 0.4, speed: 2, price: 2500, imageUrl: "https://images.unsplash.com/photo-1520633842340-0c0343a41e97?w=400" },
