    { id: 'b_factory', name: 'Ocean Titan', type: 'FACTORY_SHIP', maxFuel: 500, maxHold: 5000, resilience: 0.9, speed: 4, price: 50000, imageUrl: "https://images.unsplash.com/photo-1605218439401-d57b51b3a6cd?w=400" },
